INSERT INTO public.photos VALUES (24592, 'Lonja-Ayuntamiento c.1888', 'La calle de la Lonja con su activo ritmo vital cotidiano como continuaci‚Ēú‚Ēān del puente de Piedra que comunica con el Arrabal, al fondo. Un tranv‚Ēú¬°a "de sangre", carros tirados por caballer‚Ēú¬°as, y un heterog‚Ēú¬ģneo grupo de viandantes, bullen en el entorno de la Lonja y la Casa Consistorial. La plaza de la Seo, inmediata, se abre a la derecha. La calle del Pilar, a la izquierda. Fuente visual: Estudio Coyne (DARA-AHPZ).', 1888, 1888, 1888, 'Siglo XIX', 'CASCO HIST‚Ēú√īRICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23366682236.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23366682236.webp', 'https://www.flickr.com/photos/zaragozaantigua/23366682236/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24594, 'La Lonja 1901', 'Grupo de personas ante la Lonja, en la confluencia de la calle de Don Jaime I con la del Pilar. Fuente: www.delcampe.net', 1901, 1901, 1901, 'Anos 1900', 'CASCO HIST‚Ēú√īRICO', 41.65540500, -0.87656800, '0101000020E61000004A0B9755D80CECBF4451A04FE4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28512100995.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28512100995.webp', 'https://www.flickr.com/photos/zaragozaantigua/28512100995/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24597, 'Plaza de la Seo 1902', 'Imagen capturada junto a la fuente denominada Samaritana en la antigua plaza de la Seo, erigida no como mero ornato visual, sino como destacado punto de provisi‚Ēú‚Ēān del l‚Ēú¬°quido elemento para consumo de boca, como manifiesta la nutrida parroquia congregada en torno a ella, si bien parece que son las mujeres las que, provistas de c‚Ēú√≠ntaros de diversas capacidades, efectivamente realizan esa funci‚Ēú‚Ēān, mientras los ind‚Ēú¬°genas parecen estar vareando el agua de forma est‚Ēú‚Ēālida. Al fondo de la imagen, la calle de la Lonja y el desemboque en ella de la estilizada calle del Pilar, donde destaca el edificio de la casa de la Lonja como antigua dependencia anexa a la casa del Ayuntamiento. Esta imagen fue comercializada como vista estereosc‚Ēú‚Ēāpica de la ciudad bajo el t‚Ēú¬°tulo "The old Exchange (1551) and Plaza de La Seo, Saragossa, Spain", cuando la Lonja era curiosamente catalogada como "mercado burs‚Ēú√≠til". Fuente visual: Underwood & Underwood Publishers (Estados Unidos de Norteam‚Ēú¬ģrica), en Zaragoza estereosc‚Ēú‚Ēāpica, fotograf‚Ēú¬°a profesional y comercial 1850-1970, PUZ.', 1902, 1902, 1902, 'Anos 1900', 'CASCO HIST‚Ēú√īRICO', 41.65536300, -0.87629000, '0101000020E610000098FA7953910AECBF15014EEFE2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34255489843.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34255489843.webp', 'https://www.flickr.com/photos/zaragozaantigua/34255489843/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24603, 'Plaza de La Seo 1902', 'Imagen estereosc‚Ēú‚Ēāpica capturada en la plaza de La Seo con el fondo de la "old Exchange" (Lonja) entre la calle del Pilar (cuya esquina aparece ensanchada tras el derribo de las inmediatas casas) y el paseo del Ebro. En primer t‚Ēú¬ģrmino, la fuente de la Samaritana en su original ubicaci‚Ēú‚Ēān de la plaza como importante punto de suministro de agua. A la derecha, el seminario ,metropolitano conciliar.', 1902, 1902, 1902, 'Anos 1900', 'CASCO HIST‚Ēú√īRICO', 41.65539800, -0.87639500, '0101000020E6100000EC17EC866D0BECBF91EEE714E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51422225697.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51422225697.webp', 'https://www.flickr.com/photos/zaragozaantigua/51422225697/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24604, 'Plaza de La Seo 1878', 'Imagen capturada por el fot‚Ēú‚Ēāgrafo villanovense Gregorio Sabat‚Ēú¬ģ F‚Ēú¬ģrriz e integrada en el ‚Ēú√≠lbum "Vistas de Zaragoza", centrada en una vista del entorno de la plaza de La Seo tomada desde la altura de la vivienda del Cabildo adosada a la cara suroeste de la torre de la catedral y a la capilla de las santas Justa y Rufina. En primer t‚Ēú¬ģrmino, la plaza de La Seo con sus jardines y ‚Ēú√≠rboles vertebrados en torno a la Fuente de la Samaritana instalada en 1866. A la derecha, fachada del Seminario Conciliar construido sin demasiados remilgos sobre los restos del Palacio de la Diputaci‚Ēú‚Ēān del Reino de Arag‚Ēú‚Ēān, que fueron arrasados para la ocasi‚Ēú‚Ēān. Al fondo y a la izquierda, viviendas de la manzana de la calle de Don Jaime I comprendida entre las calles del Pilar y de Juan Mart‚Ēú¬°n Goicoechea. Aqu‚Ēú¬° figuran la n‚Ēú‚ēĎmero 7, esquinera con la calle del Pilar, y su vecina la n‚Ēú‚ēĎmero 9. Al otro lado de esa calle, la Casa-Lonja anexa a la Casa Consistorial como escenario de diversas actividades municipales y tambi‚Ēú¬ģn anual espacio donde se proced‚Ēú¬°a a la "declaraci‚Ēú‚Ēān de soldados" de los individuos que de forma obligatorio formaban parte del reemplazo de quintas (incluyendo entre ellos a quienes no pod‚Ēú¬°an permitirse la redenci‚Ēú‚Ēān en met‚Ēú√≠lico del servicio o aquellos que acud‚Ēú¬°an como "sustitutos" de los se‚Ēú‚Ėíoritos y privilegiados) y que deb‚Ēú¬°an "ingresar en caja" en torno al 1 de mayo para cumplir con los preceptivos cuatro a‚Ēú‚Ėíos de "servicio activo".', 1878, 1878, 1878, 'Siglo XIX', 'CASCO HIST‚Ēú√īRICO', 41.65519800, -0.87625600, '0101000020E6100000938FDD054A0AECBFCA332F87DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54760597074.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54760597074.webp', 'https://www.flickr.com/photos/zaragozaantigua/54760597074/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24607, 'Calle Dormer a‚Ēú‚Ėíos 20', 'Otto Wunderlich. 1920-1936. "Zaragoza. Calle Diego Dormer y La Torre de la Seo [o Catedral del Salvador en su Epifan‚Ēú¬°a, al fondo]". A la izquierda, el Palacio renacentista conocido como casa de Miguel Donlope o de la Real Maestranza de Caballer‚Ēú¬°a, por servir de sede a esta Corporaci‚Ēú‚Ēān zaragozana. Construido durante la tercera y cuarta d‚Ēú¬ģcada del siglo XVI es un ejemplo del modelo de casa-palacio aragon‚Ēú¬ģs. Fuente visual: Archivo W‚Ēú‚ēĚnderlich (WUN-05815) www.mcu.es/fototeca_patrimonio/Visor?usarVisorMCU=true&am...', 1920, 1920, 1929, 'Anos 20', 'CASCO HIST‚Ēú√īRICO', 41.65435600, -0.87653500, '0101000020E61000005B94D920930CECBF7FF8F9EFC1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14876971170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14876971170.webp', 'https://www.flickr.com/photos/zaragozaantigua/14876971170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24609, 'Torre de la Seo sin chapitel 1860', 'Un rayo incendi‚Ēú‚Ēā el chapitel de la torre de la Seo en 1850, matando al campanero. Hasta 1861 no se empez‚Ēú‚Ēā a colocar el nuevo chapitel, fundido en los talleres Julio Goybet y C‚Ēú¬°a. de Zaragoza. La peque‚Ēú‚Ėía torrecilla a la izquierda de la demediada torre de La Seo ser‚Ēú¬°a la ins‚Ēú‚Ēālita torre de la desaparecida iglesia de Santiago, sita en la calle Don Jaime I. M‚Ēú√≠s informaci‚Ēú‚Ēān sobre el suceso: tausiet.blogspot.com/2016/01/rayo-sobre-la-seo-muerte-de-... Fuente visual: Mariano J‚Ēú‚ēĎdez y Ortiz. 1859-1860. ‚Ēú√ľlbum: Andr‚Ēú¬ģs Mart‚Ēú¬°n e Ip‚Ēú√≠s. Col. Mariano Mart‚Ēú¬°n Casalderrey, Zaragoza.', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HIST‚Ēú√īRICO', 41.65470400, -0.87610700, '0101000020E6100000567E198C1109ECBFBB473657CDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14896850475.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14896850475.webp', 'https://www.flickr.com/photos/zaragozaantigua/14896850475/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24613, 'Palmeros en La Seo 1974', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 07/04/1974. Palmeros en procesi‚Ēú‚Ēān de palmas en la plaza de la Seo. A la izquierda, la catedral, con espacios se‚Ēú‚Ėíalados en suelo para aparcar en bater‚Ēú¬°a. Al fondo, la callejuela Ram‚Ēú‚Ēān Cu‚Ēú¬ģllar. A la derecha, antiguo edificio residencial de la plaza con el bar "La Cadiera" en la esquina.', 1974, 1974, 1974, 'Anos 70', 'CASCO HIST‚Ēú√īRICO', 41.65522200, -0.87608900, '0101000020E6100000BD546CCCEB08ECBF53CF8250DED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15048052115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15048052115.webp', 'https://www.flickr.com/photos/zaragozaantigua/15048052115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24618, 'Calle del Pilar a‚Ēú‚Ėíos 20', 'Calle del Pilar (derecha), esquina con la de Don Jaime I, desde la plaza de la Seo. El edificio comercial que centra la imagen tuvo distintos usos: aqu‚Ēú¬° parece ofrecer obras art‚Ēú¬°sticas de recuerdo, o souvenirs, de escultura, pintura, artesan‚Ēú¬°a. Luego fue cafeter‚Ēú¬°a y tienda de ultramarinos (Pedro Santamera), hasta desaparecer con la manzana de la que formaba parte, cuando los numerosos derribos para dar paso a la nueva gran plaza del Pilar. Fuente visual: Cr‚Ēú‚Ēānica de Zaragoza 1900-1920.', 1920, 1920, 1929, 'Anos 20', 'CASCO HIST‚Ēú√īRICO', 41.65542400, -0.87667200, '0101000020E610000087342A70B20DECBFBA8102EFE4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15472718210.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15472718210.webp', 'https://www.flickr.com/photos/zaragozaantigua/15472718210/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24619, 'Dormer 1973', 'Archivo Municipal. Gerardo Sancho Ramo. Julio 1973. Los "Gigantes", como los "Cabezudos", no pisan mucho las calles en julio, pero ese a‚Ēú‚Ėío estaba justificada la sofoquina: se estaban rodando im‚Ēú√≠genes para la pel‚Ēú¬°cula "Gigantes y Cabezudos", basada en la zarzuela del mismo t‚Ēú¬°tulo, y uno de los fragmentos recog‚Ēú¬°a, precisamente, la Salida de los Gigantes y Cabezudos en el entorno de La Seo y la actual plaza de San Bruno, mientras sonaban acordes musicales asociados, y la interpretaci‚Ēú‚Ēān de √Ē√á¬£Cuando era ni‚Ēú‚Ėía y jugaba√Ē√á√ė. Esta pel‚Ēú¬°cula estaba producida por TVE, dirigida por Jos‚Ēú¬ģ Antonio P‚Ēú√≠ramo, y actuada (las piezas musicales estaban dobladas) por destacadas personalidades de la interpretaci‚Ēú‚Ēān. Se estren‚Ēú‚Ēā de octubre de ese a‚Ēú‚Ėío, con gran ‚Ēú¬ģxito. En la imagen, durante una pausa del rodaje la chiquiller‚Ēú¬°a juega entre los Gigantes, que descansan junto a la calle Dormer, en el antiguo barrio de la Seo.', 1973, 1973, 1973, 'Anos 70', 'CASCO HIST‚Ēú√īRICO', 41.65458900, -0.87626600, '0101000020E6100000761893FE5E0AECBF22A98592C9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15476308213.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15476308213.webp', 'https://www.flickr.com/photos/zaragozaantigua/15476308213/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24625, 'Roscones 1916', 'Foto S‚Ēú√≠nchez Rom‚Ēú√≠n. La Hormiga de Oro, febrero de 1916. Venta de roscones el d‚Ēú¬°a de San Valero en la puerta de la Seo de Zaragoza, el 29 de enero de 1916.', 1916, 1916, 1916, 'Anos 10', 'CASCO HIST‚Ēú√īRICO', 41.65518200, -0.87613800, '0101000020E6100000170D198F5209ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18530408643.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18530408643.webp', 'https://www.flickr.com/photos/zaragozaantigua/18530408643/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24626, 'Gran cloaca de Caesar Augusta siglo I', '‚Ēú√ępoca de Tiberio. 14-37 d.C. Detalle del interior de la gran cloaca de Caesar Augusta bajo la actual plaza de La Seo. Se halla musealizada junto a los restos del foro. Desde el Renacimiento se utiliz‚Ēú‚Ēā como pasadizo subterr‚Ēú√≠neo, bodegas y despensas. Fuente: Cat‚Ēú√≠logo Aquaria. DPZ, 2006', 50, NULL, 99, 'Siglo XIX', 'CASCO HIST‚Ēú√īRICO', 41.65518200, -0.87613800, '0101000020E6100000170D198F5209ECBFC576F700DDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18676012115.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18676012115.webp', 'https://www.flickr.com/photos/zaragozaantigua/18676012115/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24631, 'Calle Pabostr‚Ēú¬°a 1971', 'Vista de la calle Pabostr‚Ēú¬°a con la de Dormer al fondo. A la derecha, puerta meridional de la Seo. Fuente visual: Foto Leonardo P‚Ēú¬ģrez Obis, donada por ‚Ēú√ľngel Hern‚Ēú√≠ndez Mostajo para www.rafaelcastillejo.com', 1971, 1971, 1971, 'Anos 70', 'CASCO HIST‚Ēú√īRICO', 41.65444300, -0.87620300, '0101000020E6100000DD06B5DFDA09ECBF4E0CC9C9C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22528454243.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22528454243.webp', 'https://www.flickr.com/photos/zaragozaantigua/22528454243/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24634, 'Plaza La Seo ca. 1972', 'Plaza de la Seo, con imagen de la Lonja, el Ayuntamiento, y el Pilar. Fuente visual: Foto Leonardo P‚Ēú¬ģrez Obis, donada por ‚Ēú√ľngel Hern‚Ēú√≠ndez Mostajo para www.rafaelcastillejo.com', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST‚Ēú√īRICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22754253057.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22754253057.webp', 'https://www.flickr.com/photos/zaragozaantigua/22754253057/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24636, 'Calle Cisne 1972', 'Dos ni‚Ēú‚Ėías cargadas de libros caminan por la calle del Cisne, antigua de Zaporta hasta 1863, hacia el final de la calle de Diego Dormer, al fondo. A la izquierda, anexas dependencias de la Seo, y a la derecha, inmuebles de los n‚Ēú‚ēĎmeros 2 y 4 de la calle, y tapia del patio del palacio de la Real Maestranza de Caballer‚Ēú¬°a. El recoleto barrio de La Seo, peque‚Ēú‚Ėío laberinto urbano milenario y descuidado, manten‚Ēú¬°a pese a ello la calma y el sabor.', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST‚Ēú√īRICO', 41.65478000, -0.87649300, '0101000020E6100000A088450C3B0CECBF9609BFD4CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23135317372.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23135317372.webp', 'https://www.flickr.com/photos/zaragozaantigua/23135317372/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24637, 'Plaza La Seo c.1972', 'Plaza de La Seo el d‚Ēú¬°a de San Valero. Al fondo, puente de Piedra. Fuente visual: Foto Leonardo P‚Ēú¬ģrez Obis, donada por ‚Ēú√ľngel Hern‚Ēú√≠ndez Mostajo para www.rafaelcastillejo.com', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST‚Ēú√īRICO', 41.65534100, -0.87635300, '0101000020E6100000310C5872150BECBF2D5DC136E2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23150838895.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23150838895.webp', 'https://www.flickr.com/photos/zaragozaantigua/23150838895/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24638, 'Calle San Valero c.1972', 'La calle de San Valero, antigua de la Frener‚Ēú¬°a hasta 1863, se abre desde la de Don Jaime I, y conecta con la Seo. En la imagen, solares dejados tras derribo de los inmuebles de los n‚Ēú‚ēĎmeros 5-7, 9 y 11, este ‚Ēú‚ēĎltimo esquinero con la calle de Ram‚Ēú‚Ēān Cu‚Ēú¬ģllar. A la derecha, r‚Ēú‚Ēātulo de una popular taberna sita en el local del n‚Ē¨‚ēĎ 8, que perdura. Al fondo, rotunda, la catedral del Salvador, con a‚Ēú‚Ėíejos anexos en la calle del Cisne, luego derribados.', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST‚Ēú√īRICO', 41.65501200, -0.87683600, '0101000020E61000001893FE5E0A0FECBF683EE76ED7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23158919212.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23158919212.webp', 'https://www.flickr.com/photos/zaragozaantigua/23158919212/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22737, 'C.‚Ē¨‚ēĎ de la Mosquetera 1973', 'Bicolor reba‚Ēú‚Ėío de ovejas ramonea en un campo inmediato al camino de la Mosquetera y compone una t‚Ēú¬°pica visi‚Ēú‚Ēān de la periferia de la ciudad del momento, tomada a espaldas de la avenida de G‚Ēú‚Ēāmez Laguna. De fondo esc‚Ēú¬ģnico, y de izquierda a derecha, viviendas del principio de la calle de Mar‚Ēú¬°a Guerrero, en el barrio de La Bozada; pabell‚Ēú‚Ēān de la Infanta Isabel y el de Pensionistas del arbolado Hospital Psiqui‚Ēú√≠trico Nuestra Se‚Ēú‚Ėíora del Pilar; grandes bloques en construcci‚Ēú‚Ēān que a‚Ēú‚Ėíos m‚Ēú√≠s tarde quedar‚Ēú√≠n en una esquinera ubicaci‚Ēú‚Ēān entre la prolongaci‚Ēú‚Ēān de la calle de la Duquesa de Villahermosa y la nueva V‚Ēú¬°a Universitas; y finalmente, a la derecha, el bloque del n‚Ē¨‚ēĎ 9 de la calle de Santa Rita de Casia. En el transcurso de unos cuantos a‚Ēú‚Ėíos, este escenario conocer‚Ēú¬°a una radical transformaci‚Ēú‚Ēān. Fuente visual: Gerardo Sancho Ramo, AMZ.', 1973, 1973, 1973, 'Anos 70', 'UNIVERSIDAD', 41.64267000, -0.90821600, '0101000020E6100000A58636001B10EDBF670FB40243D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31481183387.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31481183387.webp', 'https://www.flickr.com/photos/zaragozaantigua/31481183387/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24640, 'Plaza de Santa Marta 1976', 'Imagen, desde la plaza de Santa Marta, del antiguo palacio del marquesado de Huarte. Este edificio se‚Ēú‚Ėíorial fue construido a principios del siglo XVI seg‚Ēú‚ēĎn la planta est‚Ēú√≠ndar de las casonas nobles en la ciudad (gran patio central en torno al que se ordenan las estancias, con entrada por la antigua calle de Zaporta, luego Dormer, y esquina a Pabostria). A mediados del pasado siglo XX pas‚Ēú‚Ēā a propiedad de una entidad local de ahorro, hasta que a finales de los a‚Ēú‚Ėíos 70 ‚Ēú¬ģsta negoci‚Ēú‚Ēā su conversi‚Ēú‚Ēān en sede estable del Archivo Hist‚Ēú‚Ēārico Provincial, hasta ese momento en el antiguo palacio de Sobradiel, sede del Colegio de Notarios. La imagen captura las obras de restauraci‚Ēú‚Ēān y acondicionamiento del antiguo palacio, que comenzar‚Ēú√≠ a funcionar como AHPZ en 1980, con documentaci‚Ēú‚Ēān desde el siglo X de la Era, hasta el XX. A la izquierda, la calle Dormer, el antiguo palacio de la Maestranza y, al fondo, la torre y catedral de la Seo. Fuente visual: Gerardo Sancho Ramo (Archivo P‚Ēú‚ēĎblico Municipal).', 1976, 1976, 1976, 'Anos 70', 'CASCO HIST‚Ēú√īRICO', 41.65420600, -0.87650100, '0101000020E610000056293DD34B0CECBF6A6CAF05BDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23454505874.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23454505874.webp', 'https://www.flickr.com/photos/zaragozaantigua/23454505874/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24642, 'La Samaritana c.1920', 'Estatua y fuente de La Samaritana, en la plaza de La Seo. Al fondo, edificio del arzobispado. Fuente: Foto Jes‚Ēú‚ēĎs Corm‚Ēú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST‚Ēú√īRICO', 41.65531700, -0.87632100, '0101000020E610000059897956D20AECBFA4C16D6DE1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24287218474.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24287218474.webp', 'https://www.flickr.com/photos/zaragozaantigua/24287218474/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24645, 'Plaza de La Seo c.1920', 'Plaza de La Seo, con la Lonja al fondo. Fuente: Foto Jes‚Ēú‚ēĎs Corm‚Ēú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST‚Ēú√īRICO', 41.65542100, -0.87627800, '0101000020E610000087890629780AECBF490ED8D5E4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24619681880.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24619681880.webp', 'https://www.flickr.com/photos/zaragozaantigua/24619681880/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24646, 'Plaza de La Seo c.1920', 'Fuente de La Samaritana en la plaza de La Seo. Al fondo, edificio del arzobispado y Palacio Arzobispal. Fuente: Foto Jes‚Ēú‚ēĎs Corm‚Ēú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST‚Ēú√īRICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24803845901.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24803845901.webp', 'https://www.flickr.com/photos/zaragozaantigua/24803845901/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24647, 'Plaza de La Seo c.1920', 'Plaza de La Seo, con el palacio arzobispal y la portada de la catedral al fondo a la derecha, tras el arbolado. Fuente: Foto Jes‚Ēú‚ēĎs Corm‚Ēú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST‚Ēú√īRICO', 41.65528500, -0.87650300, '0101000020E61000008411FB04500CECBF9947FE60E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24803983471.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24803983471.webp', 'https://www.flickr.com/photos/zaragozaantigua/24803983471/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24648, 'La Seo 1945', 'Sello sin valor postal para recaudar fondos destinados a la construcci‚Ēú‚Ēān del "Nuevo Seminario Conciliar de Casablanca" en 1945. En este caso, representa la plaza de La Seo, con un amenazante avi‚Ēú‚Ēān que se dirige a la torre de la catedral. Parece ser que pas‚Ēú‚Ēā de largo. Fuente: www.delcampe.net', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST‚Ēú√īRICO', 41.65529300, -0.87625700, '0101000020E6100000A983BC1E4C0AECBF1C261AA4E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25475544561.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25475544561.webp', 'https://www.flickr.com/photos/zaragozaantigua/25475544561/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24649, 'Plaza de La Seo 1943', 'Foto: Josep Forns. Vista de la plaza de La Seo desde la del Pilar. Fuente: www.facebook.com/photo.php?fbid=10208829903638499&set...', 1943, 1943, 1943, 'Anos 40', 'CASCO HIST‚Ēú√īRICO', 41.65540500, -0.87656800, '0101000020E61000004A0B9755D80CECBF4451A04FE4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28145625660.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28145625660.webp', 'https://www.flickr.com/photos/zaragozaantigua/28145625660/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24654, 'Plaza de La Seo 1945', 'Imagen capturada desde la altura de la torre "Nueva", o de Nuestra Se‚Ēú‚Ėíora del Pilar del hom‚Ēú‚Ēānimo templo, con el objetivo puesto en la Lonja, la plaza de la Seo, y la fachada de la catedral de San Salvador. En primer‚Ēú¬°simo plano, a la izquierda, vista parcial del cerrado per‚Ēú¬°metral en el que estaba prevista la construcci‚Ēú‚Ēān del nuevo ayuntamiento de la ciudad. Fuente visual: postal de la editorial "Soberanas", en www.ebay.es/', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST‚Ēú√īRICO', 41.65540500, -0.87656800, '0101000020E61000004A0B9755D80CECBF4451A04FE4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34435973965.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34435973965.webp', 'https://www.flickr.com/photos/zaragozaantigua/34435973965/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24656, 'Vista desde la Seo c.1916', 'Imagen capturada desde la altura de la torre barroca de la Seo, centrada en una vista hacia el sur urbano. En primer t‚Ēú¬ģrmino, tejados en el entorno de la recoleta plaza de Santa Marta, y a la derecha, traza de la calle de Don Jaime I, donde destaca el solar dejado tras el derribo de la antigua casa del conde de Atar‚Ēú¬ģs, en la esquina con la calle de Espoz y Mina, donde poco despu‚Ēú¬ģs se construir‚Ēú¬°a el referencial inmueble dise‚Ēú‚Ėíado por Francisco Albi‚Ēú‚Ėíana, que perdura. Hacia el fondo y siguiendo al calle, atalaya de la iglesia parroquial de San Gil Abad. Hacia la izquierda, la calle de San Jorge, donde destaca la nueva sede central de la Caja de Ahorros de Zaragoza, en la esquina con la calle de San Andr‚Ēú¬ģs, donde despunta levemente la torrecilla de esta peque‚Ēú‚Ėía y hom‚Ēú‚Ēānima iglesia. Siguiendo la calle de San Jorge hacia la izquierda, emerge rotunda la antigua iglesia de San Pedro Nolasco, de planta de cruz griega. M‚Ēú√≠s hacia el fondo y a la derecha, el paseo de la Independencia. En el centro de la imagen, las torres de las dos centrales el‚Ēú¬ģctricas sitas en el entorno de la calle de San Miguel, sobre el fondo despejado de la antigua huerta de Santa Engracia que alcanza hasta la hom‚Ēú‚Ēānima iglesia parroquial.', 1916, 1916, 1916, 'Anos 10', 'CASCO HIST‚Ēú√īRICO', 41.65455700, -0.87673900, '0101000020E61000007B1684F23E0EECBF162F1686C8D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49105600518.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49105600518.webp', 'https://www.flickr.com/photos/zaragozaantigua/49105600518/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24895, 'La Samaritana c.1958', 'Plaza de La Seo con la fuente de la Samaritana fundida en Averly, trasladada en 1962 a la plaza del Justicia. Fuente. www.facebook.com/photo.php?fbid=808979045791389&set=o...', 1958, 1958, 1958, 'Anos 50', 'CASCO HIST‚Ēú√īRICO', 41.65527500, -0.87619100, '0101000020E6100000CD9541B5C109ECBF76711B0DE0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15204337611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15204337611.webp', 'https://www.flickr.com/photos/zaragozaantigua/15204337611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25158, 'Calle Dormer a‚Ēú‚Ėíos 30', 'Acuarela de Ambrosio Ruste, mostrando la calle de Diego Dormer desde la plazuela de Santa Marta. Al fondo, la torre de la Seo. A la derecha, el palacio de la Real Maestranza de Caballer‚Ēú¬°a. Fuente: L‚Ēú√≠minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST‚Ēú√īRICO', 41.65443300, -0.87652600, '0101000020E61000008FFF0241800CECBF2A36E675C4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32061502870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32061502870.webp', 'https://www.flickr.com/photos/zaragozaantigua/32061502870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25159, 'Calle Cu‚Ēú¬ģllar a‚Ēú‚Ėíos 30', 'Acuarela de Ambrosio del Ruste. Calle de Ram‚Ēú‚Ēān Cu‚Ēú¬ģllar, con la de San Valero al fondo. A la izquierda, calle del Cisne. Fuente: L‚Ēú√≠minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST‚Ēú√īRICO', 41.65481800, -0.87641900, '0101000020E61000000DFAD2DB9F0BECBF836A8313D1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32062251320.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32062251320.webp', 'https://www.flickr.com/photos/zaragozaantigua/32062251320/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25161, 'Calle Pabostr‚Ēú¬°a a‚Ēú‚Ėíos 30', 'Acuarela de Ambrosio Ruste, con una vista del palacio de la Real Maestranza de Caballer‚Ēú¬°a en la calle de Diego Dormer, al fondo, desde la de la Pabostr‚Ēú¬°a. A la derecha, puerta sur de la Seo. Fuente: L‚Ēú√≠minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST‚Ēú√īRICO', 41.65446500, -0.87630100, '0101000020E610000092770E65A80AECBF36B05582C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32062694170.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32062694170.webp', 'https://www.flickr.com/photos/zaragozaantigua/32062694170/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25165, 'Calle San Valero a‚Ēú‚Ėíos 30', 'Acuarela de Ambrosio Ruste. Al fondo de la calle San Valero, se distingue el lateral sur de la Seo. Fuente: L‚Ēú√≠minas de A. Ruste. Ayuntamiento de Zaragoza, 1977.', 1930, 1930, 1939, 'Anos 30', 'CASCO HIST‚Ēú√īRICO', 41.65490600, -0.87673000, '0101000020E6100000AE81AD122C0EECBF22FAB5F5D3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32318536381.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32318536381.webp', 'https://www.flickr.com/photos/zaragozaantigua/32318536381/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25185, 'Plaza de La Seo 1909', '"Plaza de la Seo (Zaragoza)", ‚Ēú‚Ēāleo sobre lienzo, Rafael Aguado Arnal, 1909. Colecci‚Ēú‚Ēān particular, Bilbao. Vista de la arbolada plaza de La Seo, con la catedral al fondo.', 1909, 1909, 1909, 'Anos 1900', 'CASCO HIST‚Ēú√īRICO', 41.65528900, -0.87634200, '0101000020E6100000368FC360FE0AECBFDB368C82E0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52490931279.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52490931279.webp', 'https://www.flickr.com/photos/zaragozaantigua/52490931279/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25516, 'Paza de La Seo c.1897', 'Imagen capturada en la arbolada plaza de la Seo con motivo de la Solemnidad del Cuerpo y la Sangre de Cristo durante el protocolario desfile del Ayuntamiento en Corporaci‚Ēú‚Ēān, que abre una secci‚Ēú‚Ēān de la Guardia Municipal montada en traje de gala. Al fondo, fachada e ingreso principal de la Seo, desde donde sale la procesionaria. A la izquierda, el seminario conciliar, el palacio arzobispal y el arco del Arzobispo. Fuente visual: cesbor.blogspot.com.es/', 1897, 1897, 1897, 'Siglo XIX', 'CASCO HIST‚Ēú√īRICO', 41.65536900, -0.87608300, '0101000020E6100000349C3237DF08ECBFF7E7A221E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25562239067.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25562239067.webp', 'https://www.flickr.com/photos/zaragozaantigua/25562239067/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25907, 'Plaza de la Seo 1970', 'Apacible imagen de la plaza de la Seo, cuando el articulado tranv‚Ēú¬°a 253, de la L‚Ēú¬°nea 10 "Academia" est‚Ēú√≠ presto a girar por la derecha para encaminarse al Puente de Piedra, tal y como ven‚Ēú¬°a haciendo desde los a‚Ēú‚Ėíos sesenta. Un a‚Ēú‚Ėío despu‚Ēú¬ģs de esta captura fotogr‚Ēú√≠fica, la l‚Ēú¬°nea ser‚Ēú¬°a clausurada, tras algo m‚Ēú√≠s de cuarenta a‚Ēú‚Ėíos de servicio. Justo detr‚Ēú√≠s del tranv‚Ēú¬°a, el cine "Pax" proyecta el musical "Funny Girl", con Barbra Streisand, y Omar Sharif. En la arbolada plaza, los sombreados bancos presentan notable parroquia. Fuente visual: Familia Cuy‚Ēú√°s (cartotecadigital.icc.cat/)', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST‚Ēú√īRICO', 41.65538100, -0.87630000, '0101000020E61000007B832F4CA60AECBFBBB54C86E3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24329925710.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24329925710.webp', 'https://www.flickr.com/photos/zaragozaantigua/24329925710/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22004, 'Colegio Santa In‚Ēú¬ģs 1941', 'Dibujo del proyecto de nuevo edificio para el colegio de Santa In‚Ēú¬ģs, por Lorenzo Moncl‚Ēú‚ēĎs, agosto de 1941. Ser‚Ēú√≠ levantado en 1942, en el chafl‚Ēú√≠n entre las calles de Santa In‚Ēú¬ģs y Boggiero, sobre terrenos del convento de Santa In‚Ēú¬ģs. En 1949 fue ampliado y traspasado a las dominicas de la Anunciata. Fuente: www.ebay.es', 1941, 1941, 1941, 'Anos 40', 'CASCO HIST‚Ēú√īRICO', 41.65646100, -0.89113700, '0101000020E61000007B2DE8BD3184ECBFBB0CFFE906D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36109225604.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36109225604.webp', 'https://www.flickr.com/photos/zaragozaantigua/36109225604/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23029, 'Calle del Conde de Aranda 1992', 'La calle del Conde de Aranda, tradicional salida hacia el oeste desde el centro de la ciudad, con sus 740 metros de longitud, vista desde las inmediaciones de la calle de Santa In‚Ēú¬ģs, a la izquierda, con el Coso Alto al fondo. Su configuraci‚Ēú‚Ēān cambi‚Ēú‚Ēā a‚Ēú‚Ėíos despu‚Ēú¬ģs, en virtud de una remodelaci‚Ēú‚Ēān que, finalizada en 2004, incluy‚Ēú‚Ēā aceras m‚Ēú√≠s anchas y una medianera ajardinada con palmeras.', 1992, 1992, 1992, 'Anos 90', 'CASCO HIST‚Ēú√īRICO', 41.65582500, -0.89117800, '0101000020E610000020459DB98784ECBF1973D712F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50207027816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50207027816.webp', 'https://www.flickr.com/photos/zaragozaantigua/50207027816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23919, 'Tranv‚Ēú¬°a l‚Ēú¬°nea 5 1967', 'A‚Ēú‚Ėío 1967. Tranv‚Ēú¬°a de la l‚Ēú¬°nea 5 (Venecia-Delicias), a su paso por la calle "General Franco". Detr‚Ēú√≠s del tranv‚Ēú¬°a, los restos de la manzana donde estuvo ubicada la antigua Casa de la Galera, como c‚Ēú√≠rcel correcional de mujeres durante los siglos XVII-XIX, que luego fue c‚Ēú√≠rcel masculina, y tambi‚Ēú¬ģn escuela de ni‚Ēú‚Ėíos. Fuente visual: J. Ib‚Ēú√≠‚Ēú‚Ėíez - Colecci‚Ēú‚Ēān Asociaci‚Ēú‚Ēān Filat‚Ēú¬ģlica Zaragozana "Gregorio Sierra".', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST‚Ēú√īRICO', 41.65593500, -0.89130800, '0101000020E6100000AC38D55A9885ECBFA0A696ADF5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14887018912.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14887018912.webp', 'https://www.flickr.com/photos/zaragozaantigua/14887018912/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23928, 'Calle Santa In‚Ēú¬ģs 1886', 'Vista de la calle de Santa In‚Ēú¬ģs de Zaragoza desde la iglesia del Portillo. A la derecha, calle del Portillo (hoy Conde de Aranda), flanqueada por la Casa de la Galera, reconvertida en colegio infantil en 1883. Abajo a la izquierda, huertas del convento de Santa In‚Ēú¬ģs. Al fondo, las torres de la ciudad: el Pilar, San Pablo, Santa Isabel, la Seo, la Torre Nueva...', 1886, 1886, 1886, 'Siglo XIX', 'CASCO HIST‚Ēú√īRICO', 41.65593500, -0.89130800, '0101000020E6100000AC38D55A9885ECBFA0A696ADF5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21002883458.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21002883458.webp', 'https://www.flickr.com/photos/zaragozaantigua/21002883458/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23940, 'Calle General Franco 1971', 'Vista de la calle del General Franco, esquina con la de Santa In‚Ēú¬ģs, en julio de 1971. A la derecha, los restos de la antigua Casa de la Galera, despu‚Ēú¬ģs colegio. Tras la valla con carteles comerciales, el colegio del Carmen y San Jos‚Ēú¬ģ de las Hijas de la Caridad de San Vicente de Pa‚Ēú‚ēĎl, en funcionamiento en ese lugar desde 1947, ocupando parte del terreno del convento de Santa In‚Ēú¬ģs. En el centro, unidad tranviaria n‚Ēú‚ēĎmero 80 de la l‚Ēú¬°nea 5, "Venecia-Delicias", proveniente del barrio de las Delicias. Al fondo, edificios desaparecidos de la esquina de la avenida de Madrid con el paseo de Mar‚Ēú¬°a Agust‚Ēú¬°n. A la izquierda, vista parcial de la agencia urbana n‚Ēú‚ēĎmero 1 de la Caja de Ahorros de Zaragoza y de la torre derecha de la iglesia del Portillo. Fuente visual: www.facebook.com/photo.php?fbid=1433912296624611&set=...', 1971, 1971, 1971, 'Anos 70', 'CASCO HIST‚Ēú√īRICO', 41.65580400, -0.89130000, '0101000020E6100000F697DD938785ECBF024BAE62F1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30125233381.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30125233381.webp', 'https://www.flickr.com/photos/zaragozaantigua/30125233381/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24416, 'Convento de Santa In‚Ēú¬ģs 1930', 'Defectuosa pero interesante vista de 1930 del final de la calle de San Pablo, donde tambi‚Ēú¬ģn terminaba la de Santa In‚Ēú¬ģs. Al fondo, portada del convento de Santa In‚Ēú¬ģs, enclavado ah‚Ēú¬° desde el siglo XIV, y ocupado por monjas dominicas contemplativas. A partir de 1835, se dedicaron a la ense‚Ēú‚Ėíanza. En 1942 se construy‚Ēú‚Ēā un edificio de nueva planta, en el chafl‚Ēú√≠n entre Santa In‚Ēú¬ģs y Boggiero. En 1949 se ampl‚Ēú¬°a y traspasa a las dominicas de la Anunciata. Fuente visual: Colecci‚Ēú‚Ēān Particular.', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST‚Ēú√īRICO', 41.65684600, -0.89083800, '0101000020E6100000EC1681B1BE81ECBF14419C8713D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33500671741.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33500671741.webp', 'https://www.flickr.com/photos/zaragozaantigua/33500671741/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25827, 'Calle de Boggiero 1951', 'Archivo Municipal de Zaragoza. Archivo Mora. Junio 1951. "Calle de Boggiero." Esta es una calle que nace en la calle Escuelas P‚Ēú¬°as y termina en la de Santa In‚Ēú¬ģs. Imagen del tramo entre la calle de Santa In‚Ēú¬ģs hasta la de Mayoral. A la derecha, un pedazo de la antigua Casa de la Penitencia, habilitada en el siglo XVII en un edificio del siglo XV, derribada para construir la cosa que hoy hay.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST‚Ēú√īRICO', 41.65625600, -0.89075000, '0101000020E61000001B2FDD240681ECBFE2E6543200D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15071262611.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15071262611.webp', 'https://www.flickr.com/photos/zaragozaantigua/15071262611/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25849, 'Calle de Santa In‚Ēú¬ģs 1951', 'Imagen capturada en la calle de Santa In‚Ēú¬ģs y centrada en el tramo entre la calle de Boggiero y la de San Pablo. A la izquierda, el moderno colegio de Santa In‚Ēú¬ģs, levantado en 1941 en una peque‚Ēú‚Ėía parte del antiguo convento de Santa In‚Ēú¬ģs de las Madres Dominicas. A la derecha, original anchura de la calle definida por los antiguos inmuebles del n‚Ē¨‚ēĎ 164 de Boggiero, y del n‚Ē¨‚ēĎ 6, 8 y 10-12 de Santa In‚Ēú¬ģs. Al fondo, antiguo n‚Ē¨‚ēĎ 162 de la calle de San Pablo, donde la calle de Santa In‚Ēú¬ģs terminaba, desaparecido m‚Ēú√≠s tarde con motivo de la prolongaci‚Ēú‚Ēān de esa calle hasta la de Santa Luc‚Ēú¬°a. Fuente visual: Juan Mora Insa, AMZ.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST‚Ēú√īRICO', 41.65646100, -0.89113700, '0101000020E61000007B2DE8BD3184ECBFBB0CFFE906D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/41306896562.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/41306896562.webp', 'https://www.flickr.com/photos/zaragozaantigua/41306896562/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25850, 'Calle del General Franco c.1955', 'Imagen capturada desde la altura del inmueble del n‚Ē¨‚ēĎ 81 de la calle del General Franco, y centrada en el moderno colegio de Nuestra Se‚Ēú‚Ėíora del Carmen y San Jos‚Ēú¬ģ, esquinero con la calle de Santa In‚Ēú¬ģs en primer t‚Ēú¬ģrmino y a la derecha. Casualmente y a su lado, transita una composici‚Ēú‚Ēān tranviaria M+R (posiblemente motor de la serie 60, y remolque de la 80) en servicio en la l‚Ēú¬°nea 5 "Venecia-Delicias", encaminada hacia la moderna plaza de Huesca, antigua de Rocasolano. Fuente visual: Ediciones DARVI, en www.delcampe.net/', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST‚Ēú√īRICO', 41.65582500, -0.89117800, '0101000020E610000020459DB98784ECBF1973D712F2D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46246198735.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46246198735.webp', 'https://www.flickr.com/photos/zaragozaantigua/46246198735/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20872, 'Dominguito y los barqueros 1250', 'Recuperaci‚Ēú‚Ēān del cad‚Ēú√≠ver de Santo Dominguito de Val. Museo de Huesca, siglo XVI. El ni‚Ēú‚Ėío de siete a‚Ēú‚Ėíos Dominguito de Val, infantico (monaguillo cantante) de La Seo, fue raptado por el jud‚Ēú¬°o Albayuceto, que lo entreg‚Ēú‚Ēā a sus correligionarios para que lo crucificaran (en el palacio de Sora o Salabert). Luego ocultaron su cuerpo en la ribera del Ebro tras cortarle los pies y la cabeza. Unas luces divinas mostraron el lugar a unos barqueros, que recuperaron el cuerpo. Como reza la pintura, "No es la primera ocasi‚Ēú‚Ēān que para hallar un infante se muestra el cielo radiante". Los caballeros de la barca son las autoridades que acudieron a dar fe. Esta leyenda fue creada en 1643, a imitaci‚Ēú‚Ēān de otras similares. A la izquierda, desembocadura del Huerva en el Ebro. Al fondo, puente de Tablas, puente de Piedra y Arrabal. Fuente: www.facebook.com/photo.php?fbid=10203933800178773&set...', 1250, 1250, 1250, 'Siglo XIX', 'CASCO HIST‚Ēú√īRICO', 41.65285400, -0.86416000, '0101000020E6100000105D50DF32A7EBBF098849B890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15208940932.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15208940932.webp', 'https://www.flickr.com/photos/zaragozaantigua/15208940932/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (20877, 'Dominguito de Val 1250', 'Santo Dominguito de Val. Grabado de Mateo Gonz‚Ēú√≠lez, 1793. Museo de Zaragoza. Ni‚Ēú‚Ėío legendario zaragozano del que se relataba su muerte violenta, situ‚Ēú√≠ndola en 1250, cuyo culto fue suprimido por el Concilio Vaticano II (1965). En el fondo de la imagen principal vemos una representaci‚Ēú‚Ēān del paso del r‚Ēú¬°o Ebro por Zaragoza. En el ‚Ēú√≠ngulo inferior derecho, el cad‚Ēú√≠ver mutilado luminoso en la desembocadura del r‚Ēú¬°o Huerva. A la izquierda, el Puente de Tablas y un embarcadero de dudosa verosimilitud.', 1250, 1250, 1250, 'Siglo XIX', 'CASCO HIST‚Ēú√īRICO', 41.65285400, -0.86416000, '0101000020E6100000105D50DF32A7EBBF098849B890D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19054241565.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19054241565.webp', 'https://www.flickr.com/photos/zaragozaantigua/19054241565/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22310, 'Parque Bruil c.1969', 'Imagen del "Parque Torre de Bruil" de Zaragoza, inaugurado en 1965. Fuente: Foto para postal de Comercial Josan. Cesi‚Ēú‚Ēān de la familia de Jos‚Ēú¬ģ Mar‚Ēú¬°a Sanz Gonz‚Ēú√≠lez a Rafael Castillejo. Dataci‚Ēú‚Ēān y procesado:', 1969, 1969, 1969, 'Anos 60', 'CASCO HIST‚Ēú√īRICO', 41.64977900, -0.86902400, '0101000020E6100000240D6E6B0BCFEBBF555051F52BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15679984796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15679984796.webp', 'https://www.flickr.com/photos/zaragozaantigua/15679984796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22376, 'Vista a‚Ēú¬ģrea Ebro 1964', 'Vista a‚Ēú¬ģrea del r‚Ēú¬°o Ebro a su paso por Zaragoza, desde el este. En primer t‚Ēú¬ģrmino, la desembocadura del r‚Ēú¬°o Huerva, en la margen derecha. Fuente: Colecci‚Ēú‚Ēān Rafael Margal‚Ēú¬ģ.', 1964, 1964, 1964, 'Anos 60', 'CASCO HIST‚Ēú√īRICO', 41.65381700, -0.86519600, '0101000020E610000017299485AFAFEBBFCF488446B0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22129071029.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22129071029.webp', 'https://www.flickr.com/photos/zaragozaantigua/22129071029/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (22446, 'Aloy Sala 1960', 'Imagen a‚Ēú¬ģrea capturada desde las alturas del este de la ciudad, centrada en el reciente Grupo Aloy Sala, construido en terrenos del arrabal de las Tener‚Ēú¬°as lindantes con el talud del r‚Ēú¬°o Huerva, que de izquierda a derecha, y en primer t‚Ēú¬ģrmino, desemboca en el Ebro; los campos de cultivos inmediatos a las traseras del militar Dep‚Ēú‚Ēāsito de Sementales y los terrenos de la antigua Torre de Bruil (izquierda); y la f‚Ēú√≠brica de armamento Instalaza, en el indefinido espacio hasta el cauce del r‚Ēú¬°o Ebro (derecha). Este Grupo preve‚Ēú¬°a la construcci‚Ēú‚Ēān de 1579 viviendas, locales comerciales y servicios varios, incluyendo escuelas, ocio e iglesia cat‚Ēú‚Ēālica, como g‚Ēú¬ģnesis de un nuevo barrio completo destinado a la clase media, y en r‚Ēú¬ģgimen de alquiler, a realizar en varias fases, de las que s‚Ēú‚Ēālo se completaron las dos primeras. En beneficio de todos, gratis et amore, hemos volteado horizontalmente la imagen original. Fuente visual: Arxiu Nacional de Catalunya', 1960, 1960, 1960, 'Anos 60', 'CASCO HIST‚Ēú√īRICO', 41.65209000, -0.86674900, '0101000020E61000000CE71A6668BCEBBF3A0664AF77D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31051119443.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31051119443.webp', 'https://www.flickr.com/photos/zaragozaantigua/31051119443/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
